package main

import (
	"fmt"
	"net/http"
	"os"
)

func serveFile(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("filename")
	filepath := "uploads/" + filename

	// Check if file exists
	if _, err := os.Stat(filepath); err != nil {
		fmt.Fprintf(w, "File not found: %v", err)
		return
	}

	// Open the file
	f, err := os.Open(filepath)
	if err != nil {
		fmt.Fprintf(w, "Error opening file: %v", err)
		return
	}
	defer f.Close()

	// Get the file size and content type
	stat, _ := f.Stat()
	size := stat.Size()
	contentType := http.DetectContentType(make([]byte, 1024))

	// Write headers
	w.Header().Set("Content-Type", contentType)
	w.Header().Set("Content-Length", fmt.Sprintf("%d", size))

	// Write the file content
	_, err = io.Copy(w, f)
	if err != nil {
		fmt.Fprintf(w, "Error writing to response: %v", err)
	}
}

func main() {
	http.HandleFunc("/serve-file", serveFile)
	http.ListenAndServe(":8080", nil)
}